// Implement CRUD for the accounts resource against the live DB.
// Each function receives the MongoDB db handle from src/db.mjs.
// Call ensureSchema(db) from src/schema.mjs before the first write.
import { ensureSchema } from "./schema.mjs";

const collectionName = "accounts";
const mutableFields = ["name", "tier", "status"];

function buildAccountDocument(data, createdAt = data.createdAt ?? new Date()) {
  return {
    accountId: data.accountId,
    name: data.name,
    tier: data.tier,
    status: data.status,
    createdAt,
  };
}

function pickMutableFields(data) {
  const update = {};
  for (const field of mutableFields) {
    if (data[field] !== undefined) {
      update[field] = data[field];
    }
  }
  return update;
}

// Create a accounts record. Return the created document.
export async function createAccounts(db, data) {
  await ensureSchema(db);
  const collection = db.collection(collectionName);
  const document = buildAccountDocument(data);

  await collection.deleteMany({ accountId: document.accountId });
  await collection.insertOne(document);

  return await collection.findOne({ accountId: document.accountId });
}

// Read a accounts by its id. Return the document or null.
export async function getAccounts(db, id) {
  return await db.collection(collectionName).findOne({ accountId: id });
}

// Update a accounts by id with partial data. Return the updated document.
export async function updateAccounts(db, id, data) {
  await ensureSchema(db);
  const update = pickMutableFields(data);
  if (Object.keys(update).length === 0) {
    return await getAccounts(db, id);
  }

  const collection = db.collection(collectionName);
  const result = await collection.updateOne({ accountId: id }, { $set: update });
  if (result.matchedCount === 0) {
    return null;
  }

  return await collection.findOne({ accountId: id });
}

// Delete a accounts by id. Return true if deleted.
export async function deleteAccounts(db, id) {
  const result = await db.collection(collectionName).deleteMany({ accountId: id });
  return result.deletedCount > 0;
}

import { withDb } from "./db.mjs";

const schema = {
  bsonType: "object",
  required: ["accountId", "name", "tier", "status", "createdAt"],
  additionalProperties: false,
  properties: {
    accountId: { bsonType: "string" },
    name: { bsonType: "string" },
    tier: { bsonType: "string", enum: ["strategic", "midmarket", "standard"] },
    status: { bsonType: "string", enum: ["active", "at-risk", "churned"] },
    createdAt: { bsonType: "date" },
  },
};

const collectionOptions = {
  validator: { $jsonSchema: schema },
  validationLevel: "strict",
  validationAction: "error",
};

export async function ensureSchema(db) {
  try {
    await db.createCollection("accounts", collectionOptions);
  } catch (error) {
    if (error?.code !== 48 && error?.codeName !== "NamespaceExists") {
      throw error;
    }
    await db.command({
      collMod: "accounts",
      ...collectionOptions,
    });
  }
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((db) => ensureSchema(db)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

